package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertTrue;
import static org.mockito.Mockito.mock;

import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithSkipHeaderRecord() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withSkipHeaderRecord();

        // Then
        assertTrue(result.getSkipHeaderRecord());
    }

    // Helper method to invoke private methods using reflection
    private Object invokePrivateMethod(Object object, String methodName, Class<?>[] parameterTypes, Object[] parameters)
            throws Exception {
        Method method = object.getClass().getDeclaredMethod(methodName, parameterTypes);
        method.setAccessible(true);
        return method.invoke(object, parameters);
    }
}
